import { Button, Card, CardContent, CardHeader, Container, Dialog, DialogContent, DialogTitle, Grid, List, ListItem, makeStyles, Paper, Typography } from '@material-ui/core'
import React from 'react'
import { useState } from 'react'



const useStyle = makeStyles(theme => {
    return {
        title: {
            textAlign: 'center',
            color: '#fefefe'
        },
        answers: {
            border: '1px solid #999',
            borderRadius: '7px',
            marginBottom: theme.spacing(1)
        },
        dialog: {
            backgroundColor: '#162276'
        }
    }
})

const choices = [
    {
        question: 'Sino mahal mo?',
        answerChoice: [
            {answer: 'Chanyeol', isCorrect: false},
            {answer: 'Cris Philip Vicente Cajurao', isCorrect: true},
            {answer: 'Chanyeol', isCorrect: false},
            {answer: 'Chanyeol', isCorrect: false}
        ]
    },
    {
        question: 'Sino pinakagwapo?',
        answerChoice: [
            {answer: 'Cajurao', isCorrect: true},
            {answer: 'Chanyeol', isCorrect: false},
            {answer: 'Matt Evans', isCorrect: false},
            {answer: 'Leonardo De Kapre', isCorrect: false}
        ]
    },
    {
        question: 'Birthmonth ko?',
        answerChoice: [
            {answer: 'July', isCorrect: false},
            {answer: 'August', isCorrect: false},
            {answer: 'June', isCorrect: true},
            {answer: 'September', isCorrect: false}
        ]
    },
    {
        question: 'My favorite programming language?',
        answerChoice: [
            {answer: 'Python', isCorrect: false},
            {answer: 'C++', isCorrect: false},
            {answer: 'PHP', isCorrect: false},
            {answer: 'JavaScript', isCorrect: true},
        ]
    },
    
]

export default function Quiz() {
    const classes = useStyle()
    const [quiz, setQuiz] = useState(false);
    const [currentQuestion, setCurrentQuestion] = useState(0)
    const [allDone, setAllDone] = useState(false)
    const [score, setScore] = useState(0)
    const reload = () => {window.location.reload(true)}

    const handleAnsweredQuestion = (isCorrect) => {
        if(isCorrect) {
            setScore(score + 1)
        }
        
        const nextQuestion = currentQuestion + 1
        if(nextQuestion < choices.length) {
        setCurrentQuestion(nextQuestion)
        } else {
            setAllDone(true)
        }
    }

    const openQuiz = () => {
        setQuiz(true)
    }
    const closeQuiz = () => {
        setQuiz(false)
    }
    let name = `Quiz ${currentQuestion+1}/${choices.length}`

    return (
        <div className={classes.root}>
            <Button variant='contained' color='secondary' onClick={openQuiz}>
                Open Quiz
            </Button>

            <Dialog classes={{paper: classes.dialog}} open={quiz} onClose={closeQuiz} fullScreen>
                <Typography variant='h4' className={classes.title}>Boyfriend Check</Typography>
                <DialogContent>
                    <Container maxWidth='sm'>
                    <Card elevation={10} >
                            <CardHeader align='center' title={name} subheader='Pag nasagot mo maganda ka.' />
                            <CardContent>
                                {allDone ? (
                                <Grid item xs={12}>
                                    <Typography gutterBottom textAlign='center'>
                                        You scored {score} out of {choices.length} items 
                                    </Typography>
                                    <Button onClick={reload} fullWidth variant='contained' color='secondary'>Reset</Button>
                                </Grid>
                                    ) :
                                
                                (<Grid container spacing={1}>
                                    
                                    <Grid item xs={12} lg={6}>
                                        <Typography>
                                            {currentQuestion + 1}. {choices[currentQuestion].question}
                                        </Typography>
                                    </Grid>
                                    

                                    <Grid item xs={12} lg={6}>
                                        <List>
                                            {choices[currentQuestion].answerChoice.map((choice) => (
                                                <ListItem onClick={() => handleAnsweredQuestion(choice.isCorrect)} button className={classes.answers} >{choice.answer}</ListItem>
                                            ))}
                                        </List>
                                    </Grid>

                                </Grid>
                                )}
                            </CardContent>
                    </Card>
                    </Container>
                </DialogContent>
            </Dialog>
        </div>
    )
}
